wo["WormholeStrength"] = 10
wo["WormholeRange"] = 1
ti[" "] = {"fl_himalaya"}
wo(ti, " ", 19*4+1, 12*2+1)
ti["#"] = {"st_tigris"}
ti["+"] = {"st_box_wood"}
ti["O"] = {"st_oxyd_a"}

function screens( x, y, dx, dy)
  wo:drawBorder(po(x*19, y*12), 20, 13, ti["#"])
  wo:drawBorder(po(x*19+8, y*12+1), 1, 11, ti["+"])
  wo[po(x*19+3, y*12+9)] = {"it_wormhole", destination = po(dx*19+15, dy*12+5)}
  wo[po(x*19+17, y*12+3)] = ti["O"]
end

screens(0,0, 1,0)
screens(1,0, 2,0)
screens(2,0, 3,0)
screens(3,0, 3,1)
screens(0,1, 0,0)
screens(1,1, 0,1)
screens(2,1, 1,1)
screens(3,1, 2,1)

wo[po(10,5)] = {"ac_marble"}
wo:shuffleOxyd()
